example.code:
pipeline:
  - classify:        { types: [bug, story, epic, task, spike] }
  - severity:        { levels: [blocker, critical, major, minor], arm_sla: true }
  - dedupe:          { window: 1000, threshold: 0.92, on_match: close_as_duplicate }
  - label:           { schemes: ["/area/*", "/component/*", "/lang/*"] }
  - route:           { source: CODEOWNERS }
  - assign:          { policy: least_loaded }
gates:
  on_severity_blocker:
    require: human_confirm
    via: ["/agent confirm-blocker", "oncall_slash"]
    block: [arm_sla, assign]
